'use strict'

// Only ASCII A-Z is case-folded, matching the original /[A-Z]/g replacer --
// non-ASCII characters (e.g. accented letters) are compared as-is. Exported
// so callers that need a normalized string (not just a comparison) -- e.g.
// vendor_lib/bonjour/lib/browser.js's Map keys -- fold with this exact same
// rule instead of hand-rolling a second copy that could drift out of sync.
function foldCharCode (code) {
  return (code >= 65 && code <= 90) ? code + 32 : code
}

function dnsEqual (a, b) {
  if (a.length !== b.length) return false
  for (let i = 0; i < a.length; i++) {
    if (foldCharCode(a.charCodeAt(i)) !== foldCharCode(b.charCodeAt(i))) return false
  }
  return true
}

dnsEqual.foldCharCode = foldCharCode

module.exports = dnsEqual
